// Pull the first YouTube URL out of the incoming payload (Slack event, webhook body, or ?url=).
const b = $json.body || $json;
const text = (b && b.event && b.event.text) || b.text || b.url || ($json.query && $json.query.url) || '';
const slackChannel = (b && b.event && b.event.channel) || b.channel || 'REPLACE_WITH_SLACK_CHANNEL_ID';
function clean(t) { return String(t).split('<').join('').split('>').join('').split('|')[0]; }
function isYt(t) { return t.indexOf('youtu.be/') >= 0 || (t.indexOf('youtube.com') >= 0 && (t.indexOf('watch') >= 0 || t.indexOf('/shorts/') >= 0)); }
const tokens = String(text).split('\n').join(' ').split(' ');
let videoUrl = null;
for (const tok of tokens) { const c = clean(tok); if (isYt(c)) { videoUrl = c; break; } }
if (!videoUrl) return []; // no YouTube link found — nothing to do
return [ { json: { videoUrl, slackChannel } } ];

const data = $input.first().json;
const transcriptText = (data.transcript || []).map((s) => s.text).join(' ');
const meta = data.metadata || {};
return [
  {
    json: {
      title: meta.title || null,
      videoUrl: 'https://www.youtube.com/watch?v=' + data.video_id,
      transcriptText,
      slackChannel: $('Extract YouTube URL').first().json.slackChannel,
    },
  },
];

